%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%
% SMART TRAFFIC LIGHT CONTROL USING PID CONTROLLER
% COMPLETE MINI PROJECT - GRAPH GENERATING VERSION
%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%

clc
clear
close all

disp("===============================================") %[output:459171b7]
disp("SMART TRAFFIC CONTROL USING PID CONTROLLER") %[output:1b8385c1]
disp("===============================================") %[output:47a38758]

%% ============================================================
% SIMULATION PARAMETERS
%% ============================================================

simulation_time = 300;
time_step = 1;
roads = 4;

max_green = 60;
min_green = 10;

vehicle_depart_rate = 2;

%% ============================================================
% PID PARAMETERS
%% ============================================================

Kp = 0.8;
Ki = 0.2;
Kd = 0.1;

integral_error = zeros(roads,1);
previous_error = zeros(roads,1);

%% ============================================================
% TRAFFIC PARAMETERS
%% ============================================================

queue_length = zeros(roads,1);

arrival_rate = [3;2;4;1];

vehicles_served = zeros(roads,1);
total_wait_time = zeros(roads,1);

%% ============================================================
% DATA STORAGE
%% ============================================================

queue_history = zeros(simulation_time,roads);
green_history = zeros(simulation_time,roads);

%% ============================================================
% CONTROL TARGET
%% ============================================================

desired_queue = 10;

%% ============================================================
% EMERGENCY VEHICLE
%% ============================================================

emergency_detected = false;
emergency_road = 0;

emergency_history = zeros(simulation_time,1);

%% ============================================================
% RUSH HOUR PARAMETERS
%% ============================================================

rush_hour_start = 100;
rush_hour_end = 200;

rush_hour_multiplier = 2.5;

%% ============================================================
% MAIN SIMULATION LOOP
%% ============================================================

for t = 1:simulation_time %[output:group:16941384]

    %% Rush hour adjustment
    if t >= rush_hour_start && t <= rush_hour_end
        current_arrival_rate = arrival_rate * rush_hour_multiplier;
    else
        current_arrival_rate = arrival_rate;
    end

    %% Vehicle arrivals
    for r = 1:roads

        arrivals = poissrnd(current_arrival_rate(r));

        queue_length(r) = min(queue_length(r) + arrivals , 500);

    end

    %% Emergency vehicle detection
    if rand < 0.01 && emergency_detected == false

        emergency_road = randi([1 roads]);
        emergency_detected = true;

        fprintf("Emergency vehicle detected on road %d\n",emergency_road); %[output:4f2f0ca7] %[output:607ffbd2]

    end

    emergency_history(t) = emergency_detected;

    %% Calculate green signal times
    green_time = zeros(roads,1);

    if emergency_detected

        for r = 1:roads

            if r == emergency_road
                green_time(r) = max_green;
            else
                green_time(r) = min_green;
            end

        end

    else

        for r = 1:roads

            error = queue_length(r) - desired_queue;

            integral_error(r) = integral_error(r) + error*time_step;

            if abs(integral_error(r)) > 100
                integral_error(r) = sign(integral_error(r))*100;
            end

            derivative = (error - previous_error(r))/time_step;

            output = Kp*error + Ki*integral_error(r) + Kd*derivative;

            green_time(r) = max(min_green , min_green + abs(output));

            green_time(r) = min(green_time(r) , max_green);

            previous_error(r) = error;

        end

    end

    %% Vehicle departure
    for r = 1:roads

        departing = vehicle_depart_rate * green_time(r) / 10;

        departing = min(departing , queue_length(r));

        queue_length(r) = queue_length(r) - departing;

        vehicles_served(r) = vehicles_served(r) + departing;

        total_wait_time(r) = total_wait_time(r) + queue_length(r);

    end

    %% Emergency cleared
    if emergency_detected && queue_length(emergency_road) == 0

        emergency_detected = false;

        integral_error = zeros(roads,1);
        previous_error = zeros(roads,1);

        fprintf("Emergency cleared on road %d\n",emergency_road); %[output:33d29bcb] %[output:8e14a520]

    end

    %% Store data
    queue_history(t,:) = queue_length;
    green_history(t,:) = green_time;

end %[output:group:16941384]

disp("Simulation completed") %[output:3ba6c651]

%% ============================================================
% STATISTICS
%% ============================================================

average_queue = mean(queue_history);

average_wait = zeros(roads,1);

for r = 1:roads

    if vehicles_served(r) > 0
        average_wait(r) = total_wait_time(r)/vehicles_served(r);
    else
        average_wait(r) = 0;
    end

end

total_vehicles = sum(vehicles_served);

average_system_queue = mean(queue_history(:));

max_queue = max(queue_history(:));

throughput = total_vehicles/simulation_time;

fprintf("Total Vehicles Served: %d\n",total_vehicles); %[output:74cfa61f]
fprintf("Throughput: %.2f vehicles/sec\n",throughput); %[output:10959592]

%% ============================================================
% TRAFFIC DASHBOARD
%% ============================================================

figure('Name','Traffic Dashboard') %[output:48b7e380]

subplot(2,2,1) %[output:48b7e380]

plot(queue_history,'LineWidth',1.5) %[output:48b7e380]

title("Queue Length Over Time") %[output:48b7e380]

xlabel("Time") %[output:48b7e380]

ylabel("Vehicles") %[output:48b7e380]

legend("Road1","Road2","Road3","Road4") %[output:48b7e380]

grid on %[output:48b7e380]

subplot(2,2,2) %[output:48b7e380]

area(green_history) %[output:48b7e380]

title("Green Signal Allocation") %[output:48b7e380]

xlabel("Time") %[output:48b7e380]

ylabel("Seconds") %[output:48b7e380]

grid on %[output:48b7e380]

subplot(2,2,3) %[output:48b7e380]

bar(vehicles_served) %[output:48b7e380]

title("Vehicles Served") %[output:48b7e380]

xlabel("Road") %[output:48b7e380]

ylabel("Vehicles") %[output:48b7e380]

grid on %[output:48b7e380]

subplot(2,2,4) %[output:48b7e380]

bar(average_wait) %[output:48b7e380]

title("Average Waiting Time") %[output:48b7e380]

xlabel("Road") %[output:48b7e380]

ylabel("Seconds") %[output:48b7e380]

grid on %[output:48b7e380]

sgtitle("Smart Traffic Control using PID") %[output:48b7e380]

drawnow

%% ============================================================
% TRAFFIC HEATMAP
%% ============================================================

figure('Name','Traffic Heatmap') %[output:5b3c8e90]

imagesc(queue_history') %[output:5b3c8e90]

colormap hot %[output:5b3c8e90]

colorbar %[output:5b3c8e90]

title("Traffic Density Heatmap") %[output:5b3c8e90]

xlabel("Time") %[output:5b3c8e90]

ylabel("Road") %[output:5b3c8e90]

drawnow

%% ============================================================
% FIXED SIGNAL COMPARISON
%% ============================================================

fixed_green = 30;

queue_fixed = zeros(roads,1);
history_fixed = zeros(simulation_time,roads);
vehicles_served_fixed = zeros(roads,1);

for t = 1:simulation_time

    if t >= rush_hour_start && t <= rush_hour_end
        current_arrival_rate = arrival_rate*rush_hour_multiplier;
    else
        current_arrival_rate = arrival_rate;
    end

    for r = 1:roads

        arrivals = poissrnd(current_arrival_rate(r));

        queue_fixed(r) = queue_fixed(r) + arrivals;

        served = vehicle_depart_rate*fixed_green/10;

        served = min(served , queue_fixed(r));

        queue_fixed(r) = queue_fixed(r) - served;

        vehicles_served_fixed(r) = vehicles_served_fixed(r) + served;

    end

    history_fixed(t,:) = queue_fixed;

end

total_fixed = sum(vehicles_served_fixed);

if total_fixed > 0
    improvement = ((total_vehicles-total_fixed)/total_fixed)*100;
else
    improvement = 0;
end

figure('Name','PID vs Fixed Signal') %[output:8096efcd]

plot(mean(queue_history,2),'LineWidth',2) %[output:8096efcd]

hold on %[output:8096efcd]

plot(mean(history_fixed,2),'LineWidth',2) %[output:8096efcd]

legend("PID Control","Fixed Signal") %[output:8096efcd]

title("Traffic Queue Comparison") %[output:8096efcd]

xlabel("Time") %[output:8096efcd]

ylabel("Average Queue") %[output:8096efcd]

grid on %[output:8096efcd]

drawnow

fprintf("PID improvement over fixed signal: %.2f %%\n",improvement) %[output:54d3b7b2]

%% ============================================================
% PID TUNING ANALYSIS
%% ============================================================

K_values = [0.3 0.8 1.2 1.8];

figure('Name','PID Tuning') %[output:7c1f18f5]

for i = 1:length(K_values)

    Kp_test = K_values(i);

    queue_test = zeros(roads,1);

    history_test = zeros(simulation_time,roads);

    for t = 1:simulation_time

        for r = 1:roads

            arrivals = poissrnd(arrival_rate(r));

            queue_test(r) = queue_test(r) + arrivals;

            error = queue_test(r) - desired_queue;

            green = min_green + abs(Kp_test*error);

            green = min(green , max_green);

            served = vehicle_depart_rate*green/10;

            served = min(served , queue_test(r));

            queue_test(r) = queue_test(r) - served;

        end

        history_test(t,:) = queue_test;

    end

    subplot(2,2,i) %[output:7c1f18f5]

    plot(mean(history_test,2),'LineWidth',2)

    title(['Kp = ' num2str(Kp_test)])

    xlabel("Time")

    ylabel("Queue")

    grid on

end

sgtitle("PID Tuning Analysis") %[output:7c1f18f5]

drawnow

%% ============================================================
% EXPORT RESULTS
%% ============================================================

road_vector = (1:roads)';

avg_queue_col = average_queue(:);

avg_wait_col = average_wait(:);

veh_served_col = vehicles_served(:);

results = table(road_vector,avg_queue_col,avg_wait_col,veh_served_col,...
'VariableNames',{'Road','AvgQueue','AvgWait','VehiclesServed'});

writetable(results,'traffic_results.csv');

save('traffic_workspace.mat');

%% ============================================================
% REPORT GENERATION
%% ============================================================

fid = fopen('simulation_report.txt','w');

fprintf(fid,"SMART TRAFFIC CONTROL REPORT\n\n");

fprintf(fid,"Total Vehicles Served: %d\n",total_vehicles);

fprintf(fid,"Throughput: %.2f vehicles/sec\n",throughput);

fprintf(fid,"Maximum Queue: %.0f vehicles\n",max_queue);

fprintf(fid,"Average Queue: %.2f\n\n",average_system_queue);

for r = 1:roads

fprintf(fid,"Road %d Avg Queue: %.2f\n",r,average_queue(r));

fprintf(fid,"Road %d Avg Wait: %.2f sec\n\n",r,average_wait(r));

end

fprintf(fid,"PID Improvement: %.2f %%\n",improvement);

fclose(fid);

disp("Files generated:") %[output:9de15dea]
disp("traffic_results.csv") %[output:87055bf4]
disp("traffic_workspace.mat") %[output:59310826]
disp("simulation_report.txt") %[output:7e760a97]

